#include <bits/stdc++.h>
using namespace std;
int main(){int n,m;scanf("%d %d",&n,&m);vector<long long>p(n+1,0);for(int i=1;i<=n;i++){long long x;scanf("%lld",&x);p[i]=p[i-1]+x;}string out;while(m--){int i,j;scanf("%d %d",&i,&j);out+=to_string(p[j]-p[i-1]);out+='\n';}fputs(out.c_str(),stdout);}
